// ── Notion: HTTP cru + paginação (this.helpers vem do runtime do Code node) ──
const NOTION_TOKEN = $env.NOTION_TOKEN;
const NOTION_VERSION = $env.NOTION_VERSION || '2022-06-28';
const HELPERS = this.helpers;
function notionHeaders() {
  return { Authorization: `Bearer ${NOTION_TOKEN}`, 'Notion-Version': NOTION_VERSION, 'Content-Type': 'application/json' };
}
async function notionQueryAll(databaseId, filter, sorts) {
  let results = [];
  let cursor;
  do {
    const body = { page_size: 100 };
    if (filter) body.filter = filter;
    if (sorts) body.sorts = sorts;
    if (cursor) body.start_cursor = cursor;
    const resp = await HELPERS.httpRequest({
      method: 'POST',
      url: `https://api.notion.com/v1/databases/${databaseId}/query`,
      headers: notionHeaders(),
      body,
      json: true,
    });
    results = results.concat(resp.results || []);
    cursor = resp.has_more ? resp.next_cursor : null;
  } while (cursor);
  return results;
}
async function notionCreatePage(databaseId, properties) {
  return HELPERS.httpRequest({
    method: 'POST',
    url: 'https://api.notion.com/v1/pages',
    headers: notionHeaders(),
    body: { parent: { database_id: databaseId }, properties },
    json: true,
  });
}
async function notionUpdatePage(pageId, properties) {
  return HELPERS.httpRequest({
    method: 'PATCH',
    url: `https://api.notion.com/v1/pages/${pageId}`,
    headers: notionHeaders(),
    body: { properties },
    json: true,
  });
}

// ── Glue: lê Dicionário (origem=conta) e Lançamentos (origem=conta, p/ marco d'água) ──
const filtroConta = { property: 'Origem', select: { equals: 'conta' } };
const [dicionario, lancamentosExistentes] = await Promise.all([
  notionQueryAll($env.NOTION_DB_DICIONARIO, filtroConta),
  notionQueryAll($env.NOTION_DB_LANCAMENTOS, filtroConta),
]);
return [{ json: { dicionario, lancamentos_existentes: lancamentosExistentes } }];

// Parser do extrato C6 conta corrente — lógica pura do Code node do workflow
// ingestao-csv-conta. Implementa gstack/plans/ingestao-csv-conta.md.
// splitLinha é duplicado de parser-cartao.js de propósito: cada arquivo precisa ser
// autocontido para ser embutido no Code node do n8n.

const COLUNAS = [
  "Data Lançamento", "Data Contábil", "Título", "Descrição",
  "Entrada(R$)", "Saída(R$)", "Saldo do Dia(R$)",
];
const LINHAS_METADATA = 8;

/** Divide uma linha CSV (RFC 4180) com separador configurável respeitando aspas. */
function splitLinha(linha, sep) {
  const campos = [];
  let atual = "";
  let dentroAspas = false;
  for (let i = 0; i < linha.length; i++) {
    const c = linha[i];
    if (c === '"') {
      if (dentroAspas && linha[i + 1] === '"') { atual += '"'; i++; }
      else dentroAspas = !dentroAspas;
    } else if (c === sep && !dentroAspas) {
      campos.push(atual); atual = "";
    } else {
      atual += c;
    }
  }
  campos.push(atual);
  return campos.map((c) => c.trim());
}

/** Valida DD/MM/YYYY. */
function validarData(ddmmyyyy) {
  if (!/^\d{2}\/\d{2}\/\d{4}$/.test(ddmmyyyy)) throw new Error(`data inválida: ${ddmmyyyy}`);
  return ddmmyyyy;
}

/**
 * Processa o extrato completo.
 * @param {string} csvText conteúdo do CSV (UTF-8, pode ter BOM)
 * @param {string} nomeArquivo identificador opaco (só para log)
 * @param {{chave: string, categoria: string}[]} dicionario regras origem=conta
 * @param {{nome: string}[]} metas metas ativas (aba Metas)
 * @returns {{lancamentos: object[], descartados: object[], avisos: string[], resumo: object}}
 */
function processarExtrato(csvText, nomeArquivo, dicionario, metas) {
  const linhas = csvText.replace(/^﻿/, "").split(/\r?\n/);
  if (linhas.length < LINHAS_METADATA + 1) {
    throw new Error(`arquivo com ${linhas.length} linhas — esperadas ${LINHAS_METADATA} de metadata + header`);
  }
  const header = splitLinha(linhas[LINHAS_METADATA], ",");
  if (JSON.stringify(header) !== JSON.stringify(COLUNAS)) {
    throw new Error(`header inesperado na linha ${LINHAS_METADATA + 1}: ${header.join(" | ")}`);
  }
  const meta = linhas.slice(0, LINHAS_METADATA).join("\n");
  const mPeriodo = /Extrato de (\d{2}\/\d{2}\/\d{4}) a (\d{2}\/\d{2}\/\d{4})/.exec(meta);
  const periodo = mPeriodo ? { inicio: mPeriodo[1], fim: mPeriodo[2] } : { inicio: "", fim: "" };

  const avisos = [];
  const descartados = [];
  const lancamentos = [];

  linhas.slice(LINHAS_METADATA + 1).forEach((texto, i) => {
    if (texto.trim() === "") return;
    const numLinha = LINHAS_METADATA + 2 + i;
    let c = splitLinha(texto, ",");
    // Quirk C6: a linha inteira pode vir envolta em aspas ("a,b,""c""...,x") — aí o
    // splitLinha (RFC 4180) colapsa ""→" e devolve a linha real como campo único.
    // Re-split do conteúdo desembrulhado p/ alinhar as colunas (amostra real linha 24).
    if (c.length === 1 && COLUNAS.length > 1) {
      const reSplit = splitLinha(c[0], ",");
      if (reSplit.length === COLUNAS.length) c = reSplit;
    }
    if (c.length !== COLUNAS.length) {
      throw new Error(`linha ${numLinha}: esperadas ${COLUNAS.length} colunas, vieram ${c.length}`);
    }
    const [dataLanc, , titulo, descricao, entradaStr, saidaStr] = c;
    validarData(dataLanc);
    const entrada = Number(entradaStr);
    const saida = Number(saidaStr);
    if (Number.isNaN(entrada) || Number.isNaN(saida)) {
      throw new Error(`linha ${numLinha}: valor inválido "${entradaStr}"/"${saidaStr}"`);
    }
    if (entrada > 0 && saida > 0) {
      throw new Error(`linha ${numLinha}: Entrada e Saída preenchidas simultaneamente`);
    }
    if (entrada === 0 && saida === 0) {
      descartados.push({ linha: numLinha, titulo });
      avisos.push(`linha ${numLinha} descartada: Entrada e Saída zeradas (${titulo})`);
      return;
    }
    const tipo = entrada > 0 ? "entrada" : "saída";
    const valor = entrada > 0 ? entrada : saida;

    // Categoria pela chave Título; pseudo-categoria resolve pela direção e
    // NUNCA chega à aba Lançamentos
    const alvo = titulo.toUpperCase();
    const regra = dicionario.find((r) => alvo.includes(r.chave.toUpperCase()));
    let categoria = regra ? regra.categoria : "";
    // Pseudo-categorias (resolvem pela direção; nunca chegam à aba Lançamentos).
    // Dois `if` independentes de igualdade exata — sem dependência de ordem.
    if (categoria === "Pagamento/Retirada") categoria = tipo === "entrada" ? "Pagamento" : "Retirada";
    // Pix recebido do próprio Marcelo = depósito p/ a casa; Pix enviado p/ ele mesmo = "Saída
    // para o Marcelo" (movimentação pessoal: aparece no fluxo de caixa, mas é NEUTRA ao rateio).
    // NÃO é "Retirada" — esta segue reservada a pgto de fatura e aplicação de CDB (transferências).
    if (categoria === "Depósito Marcelo/Retirada") categoria = tipo === "entrada" ? "Depósito Marcelo" : "Saída para o Marcelo";

    let idMeta = "";
    if (categoria.startsWith("Meta: ")) {
      const nomeMeta = categoria.slice(6);
      if (metas.some((m) => m.nome === nomeMeta)) idMeta = nomeMeta;
      else avisos.push(`meta não encontrada para categoria "${categoria}" (linha ${numLinha})`);
    }
    if (categoria === "" && alvo.includes("RESGATE") && alvo.includes("CDB")) {
      avisos.push(`resgate de CDB sem meta associada (linha ${numLinha}) — associar no fluxo de categorização`);
    }

    lancamentos.push({
      data_competencia: dataLanc,
      data_original: dataLanc,
      descricao,
      titulo,
      valor,
      categoria,
      tipo,
      origem: "conta",
      status: "confirmado",
      id_meta: idMeta,
    });
  });

  const soma = (tipo) =>
    Math.round(lancamentos.filter((l) => l.tipo === tipo).reduce((s, l) => s + l.valor, 0) * 100) / 100;
  const resumo = {
    quantidade: lancamentos.length,
    entradas: { n: lancamentos.filter((l) => l.tipo === "entrada").length, total: soma("entrada") },
    saidas: { n: lancamentos.filter((l) => l.tipo === "saída").length, total: soma("saída") },
    periodo_inicio: periodo.inicio,
    periodo_fim: periodo.fim,
    descartados: descartados.length,
    arquivo: nomeArquivo,
  };
  return { lancamentos, descartados, avisos, resumo };
}

/**
 * Normaliza uma data da planilha para "DD/MM/YYYY" (serial/ISO/ddmmyyyy → ddmmyyyy).
 * Duplicado de parser-cartao.js de propósito: o Code node precisa ser autocontido.
 */
function normalizarData(v) {
  if (v === null || v === undefined || v === "") return null;
  if (typeof v === "number" || (typeof v === "string" && /^\d+(\.\d+)?$/.test(v.trim()))) {
    const serial = Math.floor(Number(v));
    if (!Number.isFinite(serial) || serial <= 0) return null;
    const d = new Date(Date.UTC(1899, 11, 30) + serial * 86400000);
    const dd = String(d.getUTCDate()).padStart(2, "0");
    const mm = String(d.getUTCMonth() + 1).padStart(2, "0");
    return `${dd}/${mm}/${d.getUTCFullYear()}`;
  }
  const s = String(v).trim();
  let m;
  if ((m = /^(\d{2})\/(\d{2})\/(\d{4})$/.exec(s))) return `${m[1]}/${m[2]}/${m[3]}`;
  if ((m = /^(\d{4})-(\d{2})-(\d{2})/.exec(s))) return `${m[3]}/${m[2]}/${m[1]}`;
  return null;
}

/** "DD/MM/YYYY" → número YYYYMMDD comparável; null → -Infinity. */
function chaveOrdinal(ddmmyyyy) {
  if (!ddmmyyyy) return -Infinity;
  const [d, mes, a] = ddmmyyyy.split("/");
  return Number(`${a}${mes}${d}`);
}

/**
 * Filtra os lançamentos do extrato que ainda não estão na planilha, usando o
 * marco d'água (maior data_original já gravada com origem=conta) + o período do
 * arquivo para distinguir extensão legítima de reimportação retroativa.
 * A decisão de IMPORTAR é sempre por linha (`novos`); `situacao` só refina a
 * mensagem. Ver gstack/plans/dedup-importacao.md.
 * @param {object[]} lancamentos saída do parser (data_original DD/MM/YYYY)
 * @param {{origem, data_original}[]} existentes linhas atuais de Lançamentos
 * @param {{inicio, fim}} periodo resumo do parser (DD/MM/YYYY)
 * @returns {{novos: object[], ignorados: object[], marco: string|null,
 *   situacao: "vazia"|"tudo_novo"|"extensao"|"ja_importado"|"retroativo"}}
 */
function filtrarJaImportados(lancamentos, existentes, periodo) {
  // Emenda 15/06 (dep. seed-conta-pessoal): linhas previstas (parcelas futuras
  // semeadas) NÃO entram no marco d'água — senão envenenariam o marco e
  // bloqueariam o próximo extrato real. Blacklist `!== "previsto"` (e não
  // whitelist `=== "confirmado"`) para tolerar linhas sem campo `status`.
  const datasExist = (existentes || [])
    .filter((r) => String(r.origem) === "conta" && r.status !== "previsto")
    .map((r) => normalizarData(r.data_original))
    .filter(Boolean);

  if (datasExist.length === 0) {
    return { novos: lancamentos, ignorados: [], marco: null, situacao: "vazia" };
  }

  const marcoKey = Math.max(...datasExist.map(chaveOrdinal));
  const marco = datasExist.find((d) => chaveOrdinal(d) === marcoKey);

  const novos = [];
  const ignorados = [];
  for (const l of lancamentos) {
    if (chaveOrdinal(normalizarData(l.data_original)) > marcoKey) novos.push(l);
    else ignorados.push(l);
  }

  // Fim efetivo do extrato: o maior entre o período do metadata e a maior
  // data_original das próprias linhas. O fallback nas linhas evita um falso
  // "retroativo" quando o metadata de período veio ilegível (periodo vazio).
  const fimLanc = lancamentos.length
    ? Math.max(...lancamentos.map((l) => chaveOrdinal(normalizarData(l.data_original))))
    : -Infinity;
  const fimKey = Math.max(chaveOrdinal(normalizarData(periodo && periodo.fim)), fimLanc);
  let situacao;
  if (novos.length > 0) {
    situacao = ignorados.length > 0 ? "extensao" : "tudo_novo";
  } else {
    situacao = fimKey < marcoKey ? "retroativo" : "ja_importado";
  }

  return { novos, ignorados, marco, situacao };
}

// Mapeamento puro entre o shape "flat" usado pela lógica de negócio reaproveitada de
// workflows/src/*.js (parser-cartao, parser-conta, dashboard, rateio, ...) e o formato
// de properties da API do Notion (POST /v1/pages, POST /v1/databases/{id}/query).
// Sem I/O — só transformação de dados. Concatenado nos Code nodes do n8n junto com
// os módulos puros originais (ver scripts/gerar-workflow-*-notion.js).
// Implementa a Fase A de gstack (schema em workflows-harumi/README... ver plano da branch).

/** "DD/MM/YYYY" ou "YYYY-MM-DD" → "YYYY-MM-DD" (Notion exige ISO); inválido/vazio → null. */
function paraIso(data) {
  if (data === null || data === undefined || data === "") return null;
  const s = String(data).trim();
  let m;
  if ((m = /^(\d{4})-(\d{2})-(\d{2})/.exec(s))) return `${m[1]}-${m[2]}-${m[3]}`;
  if ((m = /^(\d{2})\/(\d{2})\/(\d{4})$/.exec(s))) return `${m[3]}-${m[2]}-${m[1]}`;
  return null;
}

/**
 * Texto plano de uma property title/rich_text do Notion. As demais funções de
 * leitura (paraObjeto*) devolvem "YYYY-MM-DD" para datas — mesDe()/normalizarData()
 * em workflows/src/*.js já aceitam esse formato ISO nativamente, então nenhuma
 * conversão adicional é necessária na leitura (só na escrita, via paraIso).
 */
function textoDe(prop) {
  if (!prop) return "";
  const arr = prop.title || prop.rich_text || [];
  return arr.map((t) => t.plain_text || "").join("");
}

const richText = (s) => (s ? [{ text: { content: String(s).slice(0, 2000) } }] : []);
const selectOrNull = (s) => (s ? { select: { name: String(s) } } : { select: null });
const dateOrNull = (isoOuBr) => {
  const iso = paraIso(isoOuBr);
  return iso ? { date: { start: iso } } : { date: null };
};

// ─── Lançamentos ────────────────────────────────────────────────────────────

/** Page do Notion (results[i] de um query em Lançamentos) → objeto flat esperado pelos parsers/dashboard. */
function paraObjetoLancamento(page) {
  const p = (page && page.properties) || {};
  return {
    _id: page && page.id,
    data_competencia: (p["Data Competência"] && p["Data Competência"].date && p["Data Competência"].date.start) || "",
    data_original: (p["Data Original"] && p["Data Original"].date && p["Data Original"].date.start) || "",
    descricao: textoDe(p["Descrição"]),
    titulo: "",
    valor: (p["Valor"] && p["Valor"].number) || 0,
    categoria: (p["Categoria"] && p["Categoria"].select && p["Categoria"].select.name) || "",
    tipo: (p["Tipo"] && p["Tipo"].select && p["Tipo"].select.name) || "",
    origem: (p["Origem"] && p["Origem"].select && p["Origem"].select.name) || "",
    status: (p["Status"] && p["Status"].select && p["Status"].select.name) || "",
    id_meta: textoDe(p["Meta"]),
  };
}

/** Objeto flat (saída do parser-cartao/parser-conta) → properties para criar a page no Notion. */
function propsDeLancamento(l) {
  return {
    "Descrição": { title: richText(l.descricao || l.titulo || "(sem descrição)") },
    "Valor": { number: Number(l.valor) || 0 },
    "Categoria": selectOrNull(l.categoria),
    "Tipo": selectOrNull(l.tipo),
    "Origem": selectOrNull(l.origem),
    "Status": selectOrNull(l.status),
    "Meta": { rich_text: richText(l.id_meta) },
    "Data Competência": dateOrNull(l.data_competencia),
    "Data Original": dateOrNull(l.data_original),
  };
}

/** Update parcial (PATCH) de um Lançamento: só Categoria+Meta — não toca nas demais properties. */
function propsCategoriaEMeta(categoria, idMeta) {
  return { "Categoria": selectOrNull(categoria), "Meta": { rich_text: richText(idMeta) } };
}

// ─── Dicionário ─────────────────────────────────────────────────────────────

function paraObjetoDicionario(page) {
  const p = (page && page.properties) || {};
  return {
    _id: page && page.id,
    descricao_original: textoDe(p["Descrição Original"]),
    categoria_mapeada: (p["Categoria Mapeada"] && p["Categoria Mapeada"].select && p["Categoria Mapeada"].select.name) || "",
    origem: (p["Origem"] && p["Origem"].select && p["Origem"].select.name) || "",
    criado_em: (p["Criado Em"] && p["Criado Em"].date && p["Criado Em"].date.start) || "",
  };
}

/** Dicionário lido vira { chave, categoria } (contrato de parser-cartao.categorizar / parser-conta). */
function paraDicionarioChaveCategoria(objetosDicionario) {
  return objetosDicionario.map((d) => ({ chave: d.descricao_original, categoria: d.categoria_mapeada }));
}

function propsDeDicionario(d) {
  // Criado Em nunca fica vazio: cai no dia de hoje se d.criado_em não vier preenchido.
  const criadoEm = paraIso(d.criado_em) || new Date().toISOString().slice(0, 10);
  return {
    "Descrição Original": { title: richText(d.descricao_original || "(vazio)") },
    "Categoria Mapeada": selectOrNull(d.categoria_mapeada),
    "Origem": selectOrNull(d.origem),
    "Criado Em": { date: { start: criadoEm } },
  };
}

// ─── Categorias ─────────────────────────────────────────────────────────────

function paraObjetoCategoria(page) {
  const p = (page && page.properties) || {};
  return {
    _id: page && page.id,
    nome: textoDe(p["Nome"]),
    tipo: (p["Tipo"] && p["Tipo"].select && p["Tipo"].select.name) || "",
    ativo: !!(p["Ativo"] && p["Ativo"].checkbox),
  };
}

function propsDeCategoria(c) {
  return {
    "Nome": { title: richText(c.nome || "(sem nome)") },
    "Tipo": selectOrNull(c.tipo),
    "Ativo": { checkbox: !!c.ativo },
  };
}

// ─── Metas ──────────────────────────────────────────────────────────────────
// Prazo fica RICH_TEXT (não Date): metas.js aceita "AAAA-MM" (sem dia) além de
// "AAAA-MM-DD" — um Date do Notion exige dia, então forçaria uma escolha arbitrária
// (dia 1? último dia?) que a lógica pura nunca precisou fazer. Texto preserva o
// valor exatamente como o usuário digitou em /novameta.

function paraObjetoMeta(page) {
  const p = (page && page.properties) || {};
  return {
    _id: page && page.id,
    nome: textoDe(p["Nome"]),
    orcamento_total: (p["Orçamento Total"] && p["Orçamento Total"].number) || 0,
    valor_acumulado: (p["Valor Acumulado"] && p["Valor Acumulado"].number) || 0,
    prazo: textoDe(p["Prazo"]),
    status: (p["Status"] && p["Status"].select && p["Status"].select.name) || "",
    criado_em: (p["Criado Em"] && p["Criado Em"].date && p["Criado Em"].date.start) || "",
  };
}

function propsDeMeta(m) {
  const criadoEm = paraIso(m.criado_em) || new Date().toISOString().slice(0, 10);
  return {
    "Nome": { title: richText(m.nome || "(sem nome)") },
    "Orçamento Total": { number: Number(m.orcamento_total) || 0 },
    "Valor Acumulado": { number: Number(m.valor_acumulado) || 0 },
    "Prazo": { rich_text: richText(m.prazo) },
    "Status": selectOrNull(m.status),
    "Criado Em": { date: { start: criadoEm } },
  };
}

/** Update parcial: só o cache de progresso (nunca fonte da verdade — ver metas.js). */
function propsValorAcumulado(valor) {
  return { "Valor Acumulado": { number: Number(valor) || 0 } };
}

/** Update parcial: só o Status (ex.: encerrar uma meta). */
function propsStatus(status) {
  return { "Status": selectOrNull(status) };
}

// ─── Contas Fixas ───────────────────────────────────────────────────────────
// Dia Vencimento fica RICH_TEXT (não Number): lembretes.js aceita tanto um dia
// numérico (1–31) quanto o literal "sexta-feira" (contas semanais) — um Number
// do Notion não representaria essa segunda forma.

function paraObjetoContaFixa(page) {
  const p = (page && page.properties) || {};
  return {
    _id: page && page.id,
    nome: textoDe(p["Nome"]),
    dia_vencimento: textoDe(p["Dia Vencimento"]),
    valor_esperado: (p["Valor Esperado"] && p["Valor Esperado"].number) || 0,
    // string "sim"/"não": lembretes.js/relatorio.js comparam com essa convenção
    // (normalizar(f.ativo) === "sim"), herdada do Sheets — o checkbox boolean do
    // Notion é traduzido aqui pra não precisar tocar nos dois arquivos compartilhados.
    ativo: (p["Ativo"] && p["Ativo"].checkbox) ? "sim" : "não",
  };
}

function propsDeContaFixa(c) {
  return {
    "Nome": { title: richText(c.nome || "(sem nome)") },
    "Dia Vencimento": { rich_text: richText(c.dia_vencimento) },
    "Valor Esperado": { number: Number(c.valor_esperado) || 0 },
    "Ativo": { checkbox: String(c.ativo).trim().toLowerCase() === "sim" },
  };
}

// ─── Dashboard Mensal ───────────────────────────────────────────────────────

function paraObjetoDashboardMensal(page) {
  const p = (page && page.properties) || {};
  return {
    _id: page && page.id,
    mes: textoDe(p["Mês"]),
    saidas: (p["Saídas"] && p["Saídas"].number) || 0,
    entradas: (p["Entradas"] && p["Entradas"].number) || 0,
    saldo: (p["Saldo"] && p["Saldo"].number) || 0,
    metas_ativas: (p["Metas Ativas"] && p["Metas Ativas"].number) || 0,
    gerado_em: (p["Gerado Em"] && p["Gerado Em"].date && p["Gerado Em"].date.start) || "",
  };
}

/** "MM/YYYY" → YYYYMM (número). O título "MM/YYYY" não ordena cronologicamente como
 * texto ("01/2027" vem antes de "12/2026" alfabeticamente) — esta é a coluna de apoio
